configuration.tbelDecoder:
// ---- Safe JSON parsing ----
var json = decodeToJson(payload);
if (json == null) {
  json = {};
}

// ---- Initialize containers ----
var telemetry = {};
var attributes = {}; // Reserved for future use

// ---- CASE: switch_closed ----
// Expected example:
// {"switch_closed": true}
// or
// {"switch_closed": false}
if (json.switch_closed != null) {
  attributes.switch1_closed = !!json.switch_closed;
}

// ---- Return in ThingsBoard format ----
return {
  deviceName: "lab1 station1",
  deviceType: "test",
  attributes: attributes,
  telemetry: telemetry
};
